  // --- Style & Popup ---
  function styleFunc(feature) {
    var s = feature.properties.status;
    if (s === 'active') return {color:'#006400',fillColor:'#00a838',fillOpacity:0.35,weight:1.5};
    return {color:'#b8860b',fillColor:'#ffff00',fillOpacity:0.35,weight:1.5};
  }
  function onEach(feature, layer) {
    var n = feature.properties.name || 'Unknown';
    var s = feature.properties.status || 'unknown';
    var m = (feature.properties.market || '').replace(/_/g,' ');
    layer.bindPopup('<b>WeLink: '+n+'</b><br>Market: '+m+'<br>Status: '+s);
  }

